  "task": "suggest_flowsheet_edits",
  "status": "ok",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕被选中的加热器单元 heater-2 的出口温度控制参数缺失问题生成候选提案。",
      "issues": [
        {
          "title": "出口温度控制缺少目标温度参数",
          "description": "Preheater 配置为 outlet_temperature 控制模式，但诊断指出缺少出口温度目标，导致当前快照为 invalid_parameters。",
          "severity": "error",
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 heater-2 添加出口温度目标占位参数",
          "target": {
            "type": "unit",
            "id": "heater-2"
          },
          "rationale": "heater-2 已配置为出口温度控制模式，直接诊断表明缺少 outlet temperature target。建议添加一个待确认的局部参数占位，以便用户提供或确认出口温度目标值；该提案不执行修改。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "/units/heater-2/config/outlet_temperature_target_c",
                "label": "Outlet temperature target",
                "unit": "degC",
                "reason": "Required when control_mode is outlet_temperature."
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ],
          "confidence": 0.87
        }
      ]
    }
  ]
}
